const rows = $json.data || [];
const minimumSpend = Number($node['Set Workflow Config'].json.minimum_spend_before_decision || 20);
const maxCpc = Number($node['Set Workflow Config'].json.max_cpc || 2.5);
const scaleRoas = Number($node['Set Workflow Config'].json.scale_roas || 3);

function getActionCount(row, actionType) {
  const actions = row.actions || [];
  const hit = actions.find(a => a.action_type === actionType);
  return hit ? Number(hit.value || 0) : 0;
}

function getRoas(row) {
  const roas = row.purchase_roas || [];
  if (!Array.isArray(roas) || roas.length === 0) return 0;
  return Number(roas[0].value || 0);
}

const analyzed = rows.map(row => {
  const spend = Number(row.spend || 0);
  const leads = getActionCount(row, 'lead');
  const purchases = getActionCount(row, 'purchase');
  const cpc = Number(row.cpc || 0);
  const roas = getRoas(row);
  const recommendations = [];

  if (spend >= minimumSpend && leads === 0 && purchases === 0) {
    recommendations.push({ action: 'pause_ad', reason: `Spend ${spend} with zero leads and zero purchases`, risk: 'low' });
  }

  if (cpc > maxCpc && Number(row.clicks || 0) >= 10) {
    recommendations.push({ action: 'review_creative', reason: `CPC ${cpc} is above max CPC ${maxCpc}`, risk: 'medium' });
  }

  if (roas >= scaleRoas && spend >= 50) {
    recommendations.push({ action: 'increase_budget_review', reason: `ROAS ${roas} is above scale threshold ${scaleRoas}`, risk: 'medium' });
  }

  return { ...row, spend, leads, purchases, cpc, roas, recommendations };
});

const totals = analyzed.reduce((acc, row) => {
  acc.spend += row.spend || 0;
  acc.clicks += Number(row.clicks || 0);
  acc.leads += row.leads || 0;
  acc.purchases += row.purchases || 0;
  return acc;
}, { spend: 0, clicks: 0, leads: 0, purchases: 0 });

const flagged = analyzed.filter(row => row.recommendations.length > 0);

return [{
  json: {
    mode: $node['Set Workflow Config'].json.mode,
    totals,
    flagged,
    analyzed,
    ai_prompt: `Analyze this Meta Ads data as a senior media buyer. Give executive summary, winners, losers, risks, and approval-required actions. Data: ${JSON.stringify({ totals, flagged, analyzed }).slice(0, 12000)}`
  }
}];

